import type { Metadata } from "next";

import InspectionCertificate from "./InspectionCertificate";

export const metadata: Metadata = {
  title: "検査成績書 / 品質検査 | ぐんじょう QC システム",
  description:
    "製造ロットの寸法・測定検査を記録し検査成績書を発行する画面。ロット/検査ヘッダー（品番・品名・ロット番号・製造指図・検査員・検査日時・ロットサイズ・抜取数）と総合判定（OK/NG/保留）の上に、測定項目テーブル（規格中心・上限USL・下限LSL・実測値・Cp/Cpk・判定）を表示。実測値は公差帯に対し 規格内 / 上限超過 / 下限未満 を 色＋記号＋スクリーンリーダー読み上げ で判定。工程能力 Cpk（目標 1.33）を目標マーカー付きゲージで、不良要因をパレート（降順バー＋累積%＋80%基準線）で集計し、検査員判定とサインオフ（発行→ロック→是正追記）まで行う。",
};

export default function InspectionCertificatePage() {
  return <InspectionCertificate />;
}

/**
 * 検査成績書のサンプルデータ。実機ではロット検査の計測システム / MES から取得する。
 * ここでは画面の評価用に決め打ちの 1 ロット分を保持する。
 */

export interface InspectionHeader {
  partNo: string;
  partName: string;
  drawingNo: string;
  lotNo: string;
  workOrder: string;
  inspector: string;
  inspectorId: string;
  inspectedAt: string; // ISO
  lotSize: number;
  sampleSize: number;
  line: string;
  customer: string;
}

/** 1 つの測定特性（行）。実測は抜取サンプルの代表値（平均）を入れている。 */
export interface Characteristic {
  id: string;
  /** 特性名（例: 外径 φ） */
  name: string;
  /** 測定方法・器具 */
  method: string;
  /** 単位 */
  unit: string;
  /** 規格中心値（nominal / 狙い値） */
  nominal: number;
  /** 上限規格 USL */
  usl: number;
  /** 下限規格 LSL */
  lsl: number;
  /** 実測代表値（抜取平均） */
  measured: number;
  /** ばらつき（標準偏差）— 工程能力の算出に使う */
  sigma: number;
  /** この特性で見つかった不良数（n=sampleSize 中） */
  defects: number;
}

/** 不良要因（パレート用）。count 降順で扱う。 */
export interface DefectCause {
  id: string;
  label: string;
  count: number;
}

export const header: InspectionHeader = {
  partNo: "AX-2207-13B",
  partName: "シャフト 駆動軸 (φ12 h7)",
  drawingNo: "DWG-AX2207-13-Rev.C",
  lotNo: "L240624-031",
  workOrder: "WO-2406-00871",
  inspector: "佐藤 健一",
  inspectorId: "QC-1182",
  inspectedAt: "2026-06-24T09:42:00",
  lotSize: 5000,
  sampleSize: 50,
  line: "第2機械加工ライン (MC-04)",
  customer: "株式会社みらい精機",
};

export const characteristics: Characteristic[] = [
  {
    id: "c1",
    name: "外径 φ",
    method: "マイクロメータ M-203",
    unit: "mm",
    nominal: 12.0,
    usl: 12.018,
    lsl: 11.982,
    measured: 12.002,
    sigma: 0.0036,
    defects: 0,
  },
  {
    id: "c2",
    name: "内径 (ボア)",
    method: "シリンダゲージ CG-11",
    unit: "mm",
    nominal: 8.0,
    usl: 8.022,
    lsl: 7.985,
    measured: 8.027, // USL 超過 → NG
    sigma: 0.011,
    defects: 3,
  },
  {
    id: "c3",
    name: "全長",
    method: "ノギス V-150",
    unit: "mm",
    nominal: 84.0,
    usl: 84.2,
    lsl: 83.8,
    measured: 83.74, // LSL 未満 → NG
    sigma: 0.078,
    defects: 2,
  },
  {
    id: "c4",
    name: "表面粗さ Ra",
    method: "粗さ計 SJ-310",
    unit: "µm",
    nominal: 1.6,
    usl: 3.2,
    lsl: 0,
    measured: 1.7,
    sigma: 0.21,
    defects: 0,
  },
  {
    id: "c5",
    name: "硬度 (HRC)",
    method: "ロックウェル HR-430",
    unit: "HRC",
    nominal: 58,
    usl: 62,
    lsl: 54,
    measured: 58.1,
    sigma: 0.62,
    defects: 0,
  },
  {
    id: "c6",
    name: "同軸度",
    method: "三次元測定機 CMM-7",
    unit: "mm",
    nominal: 0,
    usl: 0.02,
    lsl: 0,
    measured: 0.014,
    sigma: 0.0014,
    defects: 1,
  },
];

export const defectCauses: DefectCause[] = [
  { id: "d1", label: "寸法外れ (内径)", count: 3 },
  { id: "d2", label: "寸法外れ (全長)", count: 2 },
  { id: "d3", label: "幾何公差 (同軸度)", count: 1 },
  { id: "d4", label: "バリ・かえり", count: 1 },
  { id: "d5", label: "キズ・打痕", count: 1 },
];

/** Cpk しきい値（自動車業界の慣例: 1.33 以上で合格） */
export const CPK_TARGET = 1.33;

/** 片側公差で Cp/Cpk を算出（規格幅 / 6σ、中心ずれを Cpk に反映）。 */
export function processCapability(c: Characteristic): { cp: number; cpk: number } {
  const tol = c.usl - c.lsl;
  const cp = tol / (6 * c.sigma);
  const cpuUpper = (c.usl - c.measured) / (3 * c.sigma);
  const cpkLower = (c.measured - c.lsl) / (3 * c.sigma);
  const cpk = Math.min(cpuUpper, cpkLower);
  return { cp, cpk };
}

/** 全特性の中で最も低い Cpk（=ロットの工程能力を律速する特性）を返す。 */
export function worstCapability(list: Characteristic[]): {
  c: Characteristic;
  cp: number;
  cpk: number;
} {
  return list
    .map((c) => ({ c, ...processCapability(c) }))
    .sort((a, b) => a.cpk - b.cpk)[0];
}

/** 実測値が規格内に収まっているか。 */
export function inSpec(c: Characteristic): boolean {
  return c.measured >= c.lsl && c.measured <= c.usl;
}

/**
 * 規格内の特性に限定した最小 Cpk（=合格品の中で工程能力を律速する特性）。
 * 規格外（負の Cpk）はゲージで表現できないため、ゲージ表示はこちらを使う。
 */
export function worstInSpecCapability(list: Characteristic[]) {
  const ok = list.filter(inSpec);
  return (ok.length > 0 ? ok : list)
    .map((c) => ({ c, ...processCapability(c) }))
    .sort((a, b) => a.cpk - b.cpk)[0];
}

"use client";

import * as React from "react";
import {
  IconAlertTriangle,
  IconCircleCheck,
  IconClipboardCheck,
  IconHelpCircle,
} from "@tabler/icons-react";

import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  BarChart,
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  flagValue,
  MetadataList,
  ReferenceValue,
  RadioGroup,
  RadioGroupItem,
  SegmentedGaugeCard,
  Separator,
  SignedRecord,
  Statistic,
  Table,
  TableBody,
  TableCell,
  TableFooter,
  TableHead,
  TableHeader,
  TableRow,
  Textarea,
  type ChartDataPoint,
  type RangeFlag,
  type ReferenceRange,
  type SignedRecordValue,
} from "@gunjo/ui";

import {
  characteristics,
  CPK_TARGET,
  defectCauses,
  header,
  processCapability,
  worstInSpecCapability,
  type Characteristic,
  type DefectCause,
} from "./data";

type Judgement = "OK" | "NG" | "HOLD";

interface DefectCauseRow extends DefectCause {
  running: number;
  share: number;
  cum: number;
}

/* ------------------------------------------------------------------ helpers */

function fmtNum(v: number, digits = 3) {
  return v.toLocaleString("ja-JP", {
    minimumFractionDigits: digits,
    maximumFractionDigits: digits,
  });
}

function toRange(c: Characteristic): ReferenceRange {
  // QC の公差帯を ReferenceValue のレンジに写像する。
  // low = LSL, high = USL。規格外は「異常（critical）」扱いにして HH/LL を出す。
  return { low: c.lsl, high: c.usl, criticalLow: c.lsl, criticalHigh: c.usl };
}

// QC 向けのフラグラベル（医療の「高値/低値」ではなく「上限/下限規格 外」に上書き）。
const QC_FLAG_LABELS: Partial<Record<RangeFlag, string>> = {
  normal: "規格内",
  high: "上限規格 超過",
  low: "下限規格 未満",
  "critical-high": "上限規格 外（NG）",
  "critical-low": "下限規格 外（NG）",
};

function characteristicVerdict(c: Characteristic): "OK" | "NG" {
  return flagValue(c.measured, toRange(c)) === "normal" ? "OK" : "NG";
}

const JUDGEMENT_BADGE: Record<
  Judgement,
  { variant: "success" | "destructive" | "warning"; label: string }
> = {
  OK: { variant: "success", label: "合格 (OK)" },
  NG: { variant: "destructive", label: "不合格 (NG)" },
  HOLD: { variant: "warning", label: "保留" },
};

/* ----------------------------------------------------------- Cpk capability */

/**
 * Cpk を「ゾーン付き半円ゲージ」で表すための補助。SegmentedGaugeCard は
 * セグメント幅でアークを塗るため、Cpk 値そのものを needle で指すことはできない。
 * そこで「0→現在の Cpk まで」を 1 本のゾーンとして塗り、目標 1.33 を targetValue
 * マーカーで示す（=どこまで埋まっていれば合格か）。max は見やすさのため 2.0 固定。
 */
function CapabilityGauge({
  c,
  cpk,
}: {
  c: Characteristic;
  cpk: number;
}) {
  const pass = cpk >= CPK_TARGET;
  const max = 2.0;
  // 負の Cpk（規格外）はゲージの円弧で表現できないため 0 にクランプして塗る。
  const arcValue = Math.max(0, Math.min(cpk, max));

  const segments = [
    {
      label: pass ? "工程能力 (合格)" : "工程能力 (不足)",
      value: arcValue,
      color: pass ? ("success" as const) : ("destructive" as const),
    },
  ];

  return (
    <SegmentedGaugeCard
      title="工程能力 Cpk（合格品の律速特性）"
      description={`最小 Cpk: ${c.name}`}
      segments={segments}
      value={arcValue}
      valueLabel={cpk.toFixed(2)}
      centerLabel="Cpk"
      min={0}
      max={max}
      targetValue={CPK_TARGET}
      targetLabel={`目標 ${CPK_TARGET.toFixed(2)}`}
      totalLabel="Cpk"
      showLegend={false}
      formatValue={(v) => v.toFixed(2)}
      caption={
        pass
          ? `Cpk ${cpk.toFixed(2)} ≥ 目標 ${CPK_TARGET.toFixed(2)}：規格内の特性の工程能力は基準を満たします（破線=目標 ${CPK_TARGET.toFixed(2)}）。`
          : `Cpk ${cpk.toFixed(2)} < 目標 ${CPK_TARGET.toFixed(2)}：${c.name} の工程能力が不足。是正が必要です。`
      }
    />
  );
}

/* --------------------------------------------------------------- Pareto view */

/**
 * パレート図。@gunjo/ui には累積%ライン付きの二軸パレート専用コンポーネントが無いため、
 * BarChart（降順バー + averageValue を 80% 基準線に流用）と、累積% を併記した
 * テーブル行で構成する。累積ラインそのものは描けないのでテキストで補完している。
 */
function ParetoView() {
  const sorted = [...defectCauses].sort((a, b) => b.count - a.count);
  const total = sorted.reduce((s, d) => s + d.count, 0) || 1;

  // 累積を reduce で純関数的に算出（render 中のミューテーションを避ける）。
  const rows = sorted.reduce<
    Array<DefectCauseRow>
  >((acc, d) => {
    const runningBefore = acc.length > 0 ? acc[acc.length - 1].running : 0;
    const running = runningBefore + d.count;
    acc.push({
      ...d,
      running,
      share: (d.count / total) * 100,
      cum: (running / total) * 100,
    });
    return acc;
  }, []);

  // 80% 基準線を averageValue として渡す（BarChart はこれを破線で描く）。
  const eightyPct = total * 0.8;

  const bars: ChartDataPoint[] = rows.map((r) => ({
    label: r.label,
    value: r.count,
    color: r.cum <= 80 ? ("warning" as const) : ("muted" as const),
  }));

  return (
    <Card>
      <CardHeader>
        <CardTitle as="h3" className="text-base">
          不良要因の集計（パレート）
        </CardTitle>
        <p className="text-sm text-muted-foreground">
          不良 {total} 件を要因別に多い順で集計。破線は累積 80% ライン（重点改善の目安）。
        </p>
      </CardHeader>
      <CardContent className="space-y-4">
        <BarChart
          data={bars}
          variant="horizontal"
          showValues
          averageValue={eightyPct}
          averageLabel="累積80%ライン (件数換算)"
          formatValue={(v) => `${v}件`}
        />

        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>要因</TableHead>
              <TableHead className="text-right">件数</TableHead>
              <TableHead className="text-right">構成比</TableHead>
              <TableHead className="text-right">累積%</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {rows.map((r) => {
              const within80 = r.cum <= 80;
              return (
                <TableRow key={r.id}>
                  <TableCell className="font-medium">
                    <span className="inline-flex items-center gap-2">
                      {r.label}
                      {within80 ? (
                        <Badge variant="warning">重点</Badge>
                      ) : null}
                    </span>
                  </TableCell>
                  <TableCell className="text-right tabular-nums">{r.count}</TableCell>
                  <TableCell className="text-right tabular-nums">
                    {r.share.toFixed(1)}%
                  </TableCell>
                  <TableCell className="text-right tabular-nums font-medium">
                    {r.cum.toFixed(1)}%
                  </TableCell>
                </TableRow>
              );
            })}
          </TableBody>
          <TableFooter>
            <TableRow>
              <TableCell className="font-semibold">合計</TableCell>
              <TableCell className="text-right tabular-nums font-semibold">
                {total}
              </TableCell>
              <TableCell className="text-right tabular-nums">100.0%</TableCell>
              <TableCell className="text-right tabular-nums">—</TableCell>
            </TableRow>
          </TableFooter>
        </Table>
      </CardContent>
    </Card>
  );
}

/* ------------------------------------------------------- Measurement table */

function MeasurementTable() {
  return (
    <Table>
      <caption className="sr-only">
        測定項目ごとの規格値・上限・下限・実測値・工程能力・判定の一覧
      </caption>
      <TableHeader>
        <TableRow>
          <TableHead className="min-w-[8rem]">測定項目 / 方法</TableHead>
          <TableHead className="text-right">規格中心</TableHead>
          <TableHead className="text-right">下限 LSL</TableHead>
          <TableHead className="text-right">上限 USL</TableHead>
          <TableHead className="text-right">実測値 (判定)</TableHead>
          <TableHead className="text-right">Cp / Cpk</TableHead>
          <TableHead className="text-center">判定</TableHead>
        </TableRow>
      </TableHeader>
      <TableBody>
        {characteristics.map((c) => {
          const verdict = characteristicVerdict(c);
          const { cp, cpk } = processCapability(c);
          // 工程能力の 3 段階: 合格(≥1.33) / 要注意(1.0–1.33) / 能力不足(<1.0)
          const cpkLevel: "ok" | "warn" | "bad" =
            cpk >= CPK_TARGET ? "ok" : cpk >= 1.0 ? "warn" : "bad";
          const cpkClass =
            cpkLevel === "ok"
              ? "text-foreground"
              : cpkLevel === "warn"
                ? "text-warning"
                : "text-destructive";
          const cpkSr =
            cpkLevel === "ok"
              ? "工程能力 合格"
              : cpkLevel === "warn"
                ? "工程能力 要注意"
                : "工程能力 不足";
          const digits = c.unit === "HRC" ? 1 : 3;
          return (
            <TableRow key={c.id}>
              <TableCell>
                <span className="font-medium text-foreground">{c.name}</span>
                <span className="block text-xs text-muted-foreground">
                  {c.method}・{c.unit}
                </span>
              </TableCell>
              <TableCell className="text-right tabular-nums text-muted-foreground">
                {fmtNum(c.nominal, digits)}
              </TableCell>
              <TableCell className="text-right tabular-nums text-muted-foreground">
                {fmtNum(c.lsl, digits)}
              </TableCell>
              <TableCell className="text-right tabular-nums text-muted-foreground">
                {fmtNum(c.usl, digits)}
              </TableCell>
              <TableCell className="text-right">
                <span className="inline-flex justify-end">
                  <ReferenceValue
                    value={c.measured}
                    range={toRange(c)}
                    unit={c.unit}
                    labels={QC_FLAG_LABELS}
                    format={(v) => fmtNum(v, digits)}
                    size="inline"
                  />
                </span>
              </TableCell>
              <TableCell className="text-right tabular-nums">
                <span className={cpkClass}>
                  {cp.toFixed(2)} / {cpk.toFixed(2)}
                </span>
                <span className="sr-only">{cpkSr}</span>
              </TableCell>
              <TableCell className="text-center">
                {verdict === "OK" ? (
                  <Badge variant="success">
                    <IconCircleCheck className="mr-0.5 h-3 w-3" aria-hidden="true" />
                    OK
                  </Badge>
                ) : (
                  <Badge variant="destructive">
                    <IconAlertTriangle className="mr-0.5 h-3 w-3" aria-hidden="true" />
                    NG
                  </Badge>
                )}
              </TableCell>
            </TableRow>
          );
        })}
      </TableBody>
    </Table>
  );
}

/* --------------------------------------------------------------- main screen */

export default function InspectionCertificate() {
  const ngList = characteristics.filter((c) => characteristicVerdict(c) === "NG");
  const okCount = characteristics.length - ngList.length;
  // 不良「品」数 = 規格外を 1 つ以上含むサンプル数（特性ごとの不良数の最大で近似）。
  const defectiveUnits = characteristics.reduce((m, c) => Math.max(m, c.defects), 0);
  // 不良「発生」数 = パレートの要因別件数の合計（1 品で複数要因あり得る）。
  const totalOccurrences = defectCauses.reduce((s, d) => s + d.count, 0);
  const defectRate = defectiveUnits / header.sampleSize;
  const worstInSpec = worstInSpecCapability(characteristics);

  // 既定の総合判定: 規格外の特性があれば NG、なければ（工程能力で）OK。
  const autoVerdict: Judgement = ngList.length > 0 ? "NG" : "OK";
  const [verdict, setVerdict] = React.useState<Judgement>(autoVerdict);
  const [comment, setComment] = React.useState(
    ngList.length > 0
      ? "内径および全長が規格外。該当ロットは出荷保留とし、特別採用 (特採) 可否を技術部門に確認する。"
      : ""
  );

  const [record, setRecord] = React.useState<SignedRecordValue>({
    status: "draft",
    addenda: [],
  });

  const verdictMeta = JUDGEMENT_BADGE[verdict];

  const headerItems = [
    { label: "品番", value: header.partNo },
    { label: "品名", value: header.partName },
    { label: "図番", value: header.drawingNo },
    { label: "ロット番号", value: header.lotNo },
    { label: "製造指図", value: header.workOrder },
    { label: "ライン", value: header.line },
    { label: "検査員", value: `${header.inspector}（${header.inspectorId}）` },
    {
      label: "検査日時",
      value: new Date(header.inspectedAt).toLocaleString("ja-JP", {
        year: "numeric",
        month: "2-digit",
        day: "2-digit",
        hour: "2-digit",
        minute: "2-digit",
      }),
    },
    { label: "ロットサイズ", value: `${header.lotSize.toLocaleString("ja-JP")} 個` },
    { label: "抜取数 (n)", value: `${header.sampleSize} 個` },
    { label: "客先", value: header.customer },
  ];

  return (
    <main className="mx-auto w-full max-w-5xl px-4 py-6 sm:px-6 sm:py-8">
      {/* ---- ページ見出し + 総合判定 ---- */}
      <header className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-start sm:justify-between">
        <div className="space-y-1">
          <p className="inline-flex items-center gap-1.5 text-xs font-medium uppercase tracking-wide text-muted-foreground">
            <IconClipboardCheck className="h-4 w-4" aria-hidden="true" />
            品質検査
          </p>
          <h1 className="text-2xl font-bold tracking-tight text-foreground sm:text-3xl">
            検査成績書
          </h1>
          <p className="text-sm text-muted-foreground">
            {header.partName}（{header.partNo}） / ロット {header.lotNo}
          </p>
        </div>
        <div className="flex shrink-0 flex-col items-start gap-1 sm:items-end">
          <span className="text-xs text-muted-foreground">総合判定</span>
          <Badge
            variant={verdictMeta.variant}
            className="h-7 px-3 text-sm"
            aria-live="polite"
          >
            {verdictMeta.label}
          </Badge>
        </div>
      </header>

      {/* ---- NG サマリ警告 ---- */}
      {ngList.length > 0 ? (
        <Alert variant="destructive" className="mb-6">
          <IconAlertTriangle aria-hidden="true" />
          <AlertTitle as="h2">規格外の測定項目が {ngList.length} 件あります</AlertTitle>
          <AlertDescription>
            {ngList.map((c) => c.name).join("・")} が公差を外れています。
            該当ロットは合否判定・サインオフの前に措置（保留 / 特採 / 廃却）の決定が必要です。
          </AlertDescription>
        </Alert>
      ) : null}

      {/* ---- KPI サマリ ---- */}
      <section aria-labelledby="summary-heading" className="mb-6">
        <h2 id="summary-heading" className="sr-only">
          ロットサマリ
        </h2>
        <div className="grid grid-cols-2 gap-3 lg:grid-cols-4">
          <Statistic
            label="合格項目"
            value={`${okCount} / ${characteristics.length}`}
            hint="測定特性の合否"
          />
          <Statistic
            label={`不良品数 (n=${header.sampleSize}中)`}
            value={`${defectiveUnits} 個`}
            tone={defectiveUnits > 0 ? "negative" : "positive"}
            trend={defectiveUnits > 0 ? "up" : "flat"}
            change={`不良率 ${(defectRate * 100).toFixed(1)}%`}
            hint={`不良発生 ${totalOccurrences} 件`}
          />
          <Statistic
            label="最小 Cpk (規格内)"
            value={worstInSpec.cpk.toFixed(2)}
            tone={worstInSpec.cpk >= CPK_TARGET ? "positive" : "negative"}
            trend={worstInSpec.cpk >= CPK_TARGET ? "flat" : "down"}
            change={`目標 ${CPK_TARGET.toFixed(2)}`}
            hint={worstInSpec.c.name}
          />
          <Statistic
            label="抜取数 / ロット"
            value={`${header.sampleSize} / ${header.lotSize.toLocaleString("ja-JP")}`}
            hint="AQL 抜取検査"
          />
        </div>
      </section>

      {/* ---- ロット / 検査ヘッダー ---- */}
      <Card className="mb-6">
        <CardHeader>
          <CardTitle as="h2" className="text-base">
            ロット・検査情報
          </CardTitle>
        </CardHeader>
        <CardContent>
          <MetadataList items={headerItems} layout="horizontal" />
        </CardContent>
      </Card>

      {/* ---- 測定項目テーブル ---- */}
      <section aria-labelledby="measure-heading" className="mb-6">
        <div className="mb-3 flex items-center justify-between gap-3">
          <h2 id="measure-heading" className="text-lg font-semibold tracking-tight">
            測定項目
          </h2>
          <p className="text-xs text-muted-foreground">
            実測値は抜取 {header.sampleSize} 個の代表値（平均）
          </p>
        </div>
        <MeasurementTable />
        <p className="mt-2 text-xs text-muted-foreground">
          判定基準: 実測値が 下限規格 (LSL) 〜 上限規格 (USL) の範囲内なら OK、
          範囲外は NG。公差外は値の色・記号・スクリーンリーダー読み上げで表示します。
        </p>
      </section>

      {/* ---- 工程能力 + パレート（2カラム） ---- */}
      <section aria-labelledby="analysis-heading" className="mb-6">
        <h2 id="analysis-heading" className="mb-3 text-lg font-semibold tracking-tight">
          工程能力 / 不良要因分析
        </h2>
        <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
          <CapabilityGauge c={worstInSpec.c} cpk={worstInSpec.cpk} />
          <ParetoView />
        </div>
      </section>

      <Separator className="my-6" />

      {/* ---- 判定・サインオフ ---- */}
      <section aria-labelledby="signoff-heading">
        <h2 id="signoff-heading" className="mb-3 text-lg font-semibold tracking-tight">
          判定・サインオフ
        </h2>
        <Card>
          <CardContent className="space-y-5 pt-6">
            <SignedRecord
              value={record}
              onChange={setRecord}
              signerId={`${header.inspector}（${header.inspectorId}）`}
              canSign={verdict !== "HOLD"}
              labels={{
                draft: "未確定（下書き）",
                signed: "発行・確定済",
                sign: "検査成績書を発行",
                signedByLabel: "発行者",
                locked:
                  "発行済みの検査成績書は変更できません。訂正は追記（是正記録）で行います。",
                addendaTitle: "是正・追記記録",
                addendum: "是正を追記",
                addendumBody: "是正内容",
                addendumReason: "理由 / 根拠",
                addendumSubmit: "追記して記録",
              }}
            >
              {({ readOnly }) => (
                <div className="space-y-5">
                  <fieldset disabled={readOnly} className="space-y-2">
                    <legend className="text-sm font-medium text-foreground">
                      検査員 最終判定
                    </legend>
                    <RadioGroup
                      value={verdict}
                      onValueChange={(v) => setVerdict(v as Judgement)}
                      aria-label="総合判定"
                      className="gap-3 sm:grid-flow-col sm:auto-cols-max"
                    >
                      {/* `disabled={readOnly}` を各 Item にも明示。fieldset[disabled] は
                          クリックは止めるが、role="radio" の button に aria-disabled を
                          付与しないため、確定後のロックを支援技術にも伝える保険。 */}
                      <RadioGroupItem
                        value="OK"
                        label="合格 (OK)"
                        description="全項目 規格内・出荷可"
                        disabled={readOnly}
                      />
                      <RadioGroupItem
                        value="NG"
                        label="不合格 (NG)"
                        description="規格外あり・出荷不可"
                        disabled={readOnly}
                      />
                      <RadioGroupItem
                        value="HOLD"
                        label="保留"
                        description="特採/再検査の判断待ち"
                        disabled={readOnly}
                      />
                    </RadioGroup>
                    {verdict === "HOLD" ? (
                      <p className="inline-flex items-center gap-1.5 text-xs text-warning">
                        <IconHelpCircle className="h-3.5 w-3.5" aria-hidden="true" />
                        保留中は発行できません。措置を確定してください。
                      </p>
                    ) : null}
                  </fieldset>

                  <Textarea
                    label="所見・特記事項"
                    description="不適合の措置（特採・再検査・廃却）や根拠を記載"
                    value={comment}
                    onChange={(e) => setComment(e.target.value)}
                    rows={3}
                    disabled={readOnly}
                  />

                  <div className="rounded-md border border-border bg-muted/30 p-3 text-xs text-muted-foreground">
                    判定: <span className="font-medium text-foreground">{verdictMeta.label}</span>
                    　/　最小 Cpk: {worstInSpec.cpk.toFixed(2)}（{worstInSpec.c.name}）
                    　/　不良品 {defectiveUnits} 個・発生 {totalOccurrences} 件
                  </div>
                </div>
              )}
            </SignedRecord>
          </CardContent>
        </Card>
      </section>
    </main>
  );
}
